// V17: 参数化查询重构 — 消除 SQL 注入风险
// 不再构建 WHERE 子句，只输出干净的参数值
const q = $input.item.json.query || {};
const item = (q.item || '').trim();
const whs = (q.whs || '').trim();
const bin = (q.bin || '').trim();

if (!item && !whs && !bin) {
  return { json: { _error: true, message: '请输入物料代码、仓库代码或库位' } };
}

return { json: {
  _error: false,
  p_cc: $env.DP_COMPANY_CODE || '',
  p_item: item,
  p_whs: whs,
  p_bin: bin
} };

// ==========================================
// wf08 构建响应: S(快照)/D(delta) 分开聚合
// 前端期望: base_qty / delta_qty / real_time_qty
// SQL _rt 标记: 'S' = snapshot, 'D' = delta (未过账事务)
// ==========================================
const inputRecords = $input.all().map(i => i.json);
const stockMap = new Map();

inputRecords.forEach(record => {
    const item = record.item_code || 'UNKNOWN';
    const batch = record.batch_number || '';
    const wh = record.whs_code || '';
    const loc = record.bin_code || '';
    const qty = parseFloat(record.qty) || 0;
    const rt = record._rt || 'S';

    const key = `${item}|${batch}|${wh}|${loc}`;

    if (!stockMap.has(key)) {
        stockMap.set(key, {
            item_code: item,
            item_name: record.item_name || '',
            foreign_name: record.foreign_name || '',
            item_group: record.item_group || '',
            uom: record.uom || '',
            batch_number: batch,
            whs_code: wh,
            whs_name: record.whs_name || '',
            bin_code: loc,
            base_qty: 0,
            delta_qty: 0,
            real_time_qty: 0,
            avg_price: parseFloat(record.avg_price) || 0,
            stock_value: parseFloat(record.stock_value) || 0,
            total_on_hand: parseFloat(record.total_on_hand) || 0,
            committed_qty: parseFloat(record.committed_qty) || 0,
            ordered_qty: parseFloat(record.ordered_qty) || 0,
            snapshot_date: record.snapshot_date || null
        });
    }

    const entry = stockMap.get(key);
    if (rt === 'S') {
        entry.base_qty = Math.round((entry.base_qty + qty) * 10000) / 10000;
    } else {
        entry.delta_qty = Math.round((entry.delta_qty + qty) * 10000) / 10000;
    }
    // 附加字段取最新非空值
    if (record.item_name) entry.item_name = record.item_name;
    if (record.whs_name) entry.whs_name = record.whs_name;
    if (record.foreign_name) entry.foreign_name = record.foreign_name;
    if (record.item_group) entry.item_group = record.item_group;
    if (record.uom) entry.uom = record.uom;
    if (parseFloat(record.avg_price)) entry.avg_price = parseFloat(record.avg_price);
    if (parseFloat(record.stock_value)) entry.stock_value = parseFloat(record.stock_value);
    if (parseFloat(record.total_on_hand)) entry.total_on_hand = parseFloat(record.total_on_hand);
    if (parseFloat(record.committed_qty)) entry.committed_qty = parseFloat(record.committed_qty);
    if (parseFloat(record.ordered_qty)) entry.ordered_qty = parseFloat(record.ordered_qty);
    if (record.snapshot_date) entry.snapshot_date = record.snapshot_date;
});

// 补全 delta-only 行缺失的 uom (事务表无 uom，从同 item_code 的快照行取)
const uomMap = new Map();
stockMap.forEach(entry => {
    if (entry.uom && !uomMap.has(entry.item_code)) {
        uomMap.set(entry.item_code, entry.uom);
    }
});
stockMap.forEach(entry => {
    if (!entry.uom && uomMap.has(entry.item_code)) {
        entry.uom = uomMap.get(entry.item_code);
    }
});

// 计算实时库存 = 快照 + WMS变动
const result = Array.from(stockMap.values())
    .map(s => {
        s.real_time_qty = Math.round((s.base_qty + s.delta_qty) * 10000) / 10000;
        return s;
    })
    .filter(s => Math.abs(s.base_qty) >= 0.0001 || Math.abs(s.delta_qty) >= 0.0001);

return [{ json: { success: true, data: result } }];
